import { connect } from "@tursodatabase/serverless";
const TABLE_SQL = `CREATE TABLE IF NOT EXISTS snap_kv (key TEXT PRIMARY KEY, value TEXT NOT NULL)`;
export function createInMemoryDataStore() {
    const data = new Map();
    return {
        async get(key) {
            return data.get(key) ?? null;
        },
        async set(key, value) {
            data.set(key, value);
        },
    };
}
export function createTursoDataStore() {
    const url = process.env.TURSO_DATABASE_URL;
    const authToken = process.env.TURSO_AUTH_TOKEN;
    if (!url || !authToken) {
        console.warn("missing Turso env vars -- using in-memory data store");
        return createInMemoryDataStore();
    }
    const conn = connect({ url, authToken });
    let ensureTablePromise;
    const ensureTable = async () => {
        if (!ensureTablePromise) {
            ensureTablePromise = conn.execute(TABLE_SQL).then(() => undefined);
        }
        await ensureTablePromise;
    };
    return {
        async get(key) {
            await ensureTable();
            const stmt = await conn.prepare("SELECT value FROM snap_kv WHERE key = ?");
            const row = await stmt.get([key]);
            if (row == null) {
                return null;
            }
            const text = typeof row === "object" &&
                row !== null &&
                "value" in row &&
                typeof row.value === "string"
                ? row.value
                : String(row);
            return JSON.parse(text);
        },
        async set(key, value) {
            await ensureTable();
            const stmt = await conn.prepare("INSERT OR REPLACE INTO snap_kv (key, value) VALUES (?, ?)");
            await stmt.run([key, JSON.stringify(value)]);
        },
    };
}
